const items = $input.all();

if (!items || items.length === 0) {
  console.log('Aucune DA trouvée aujourd\'hui');
  return [];
}

console.log(`${items.length} lignes DA récupérées`);

// NE PAS regrouper - garder chaque ligne séparée
const result = items.map(item => ({
  json: {
    numero_da: item.json.DA,
    code_article: item.json.Article,
    designation_article: item.json.DésignationArticle,
    famille: item.json.Famille,
    quantite: parseFloat(item.json.QteDA || 0),
    unite: item.json.Unite,
    marque_souhaitee: item.json.Marque || null,
    date_creation_da: new Date().toISOString().slice(0, 19).replace('T', ' '),
    statut: 'nouveau'
  }
}));

console.log(`${result.length} lignes DA individuelles à traiter`);
return result;

const fournisseursSageX3 = $('supprime les doublons').all();
const blacklistMySQL = $input.all();

const blacklistCodes = blacklistMySQL.map(item => item.json.code_fournisseur);

console.log(`Fournisseurs Sage X3: ${fournisseursSageX3.length}`);
console.log(`Fournisseurs blacklistés: ${blacklistCodes.length}`);

const fournisseursFiltres = [];
let nbBlacklistes = 0;
let nbEmailInvalide = 0;

for (const item of fournisseursSageX3) {
  const codeFournisseur = item.json.Fournisseur;
  const nomFournisseur = item.json.NomFournisseur;
  const email = item.json.EMAIL;

  if (blacklistCodes.includes(codeFournisseur)) {
    console.log(`SKIP: ${codeFournisseur} (${nomFournisseur}) - Blacklisté`);
    nbBlacklistes++;
    continue;
  }

  if (!email || email.trim() === '' || !email.includes('@')) {
    console.log(`SKIP: ${codeFournisseur} (${nomFournisseur}) - Email invalide`);
    nbEmailInvalide++;
    continue;
  }

  fournisseursFiltres.push(item);
  console.log(`OK: ${codeFournisseur} (${nomFournisseur}) - ${email}`);
}

console.log('\nRESUME FILTRAGE:');
console.log(`   Total: ${fournisseursSageX3.length}`);
console.log(`   Blacklistes: ${nbBlacklistes}`);
console.log(`   Email invalide: ${nbEmailInvalide}`);
console.log(`   Valides: ${fournisseursFiltres.length}`);

if (fournisseursFiltres.length === 0) {
  const articleInfo = $('🏷️ Set Article Code').first().json;
  console.error(`ALERTE: Aucun fournisseur valide pour article ${articleInfo.article_code}`);
}

return fournisseursFiltres;

const items = $input.all();
if (!items || items.length === 0) {
  console.log('⚠️ Aucun fournisseur à traiter');
  return [];
}
console.log(`\n📦 ${items.length} fournisseurs (après filtrage blacklist)`);

// ─── Groupement normal par fournisseur ───────────────────────────────────────
const grouped = {};
for (const item of items) {
  const data = item.json;
  const fournisseur = data.Fournisseur;

  if (!grouped[fournisseur]) {
    grouped[fournisseur] = {
      code_fournisseur: data.Fournisseur,
      nom_fournisseur: data.NomFournisseur,
      email: data.EMAIL,
      telephone: data.TELE,
      fax: data.FAX,
      Articles: []
    };
  }

  grouped[fournisseur].Articles.push({
    numero_da: data.DA,
    code_article: data.Article_Code || data.Article,
    designation: data.Designation || data.DescriptionFinale,
    quantite_demandee: parseFloat(data.QTY),
    unite: data.UNITE,
    marque_souhaitee: data.MARQ
  });
}

// ─── Fournisseur statique : reçoit TOUS les articles ─────────────────────────
const tousLesArticles = items.map(item => ({
  numero_da: item.json.DA,
  code_article: item.json.Article_Code || item.json.Article,
  designation: item.json.Designation || item.json.DescriptionFinale,
  quantite_demandee: parseFloat(item.json.QTY),
  unite: item.json.UNITE,
  marque_souhaitee: item.json.MARQ
}));

// Dédupliquer les articles du fournisseur statique (même article + même DA)
const articlesUniques = [];
const seen = new Set();
for (const art of tousLesArticles) {
  const key = `${art.code_article}_${art.numero_da}`;
  if (!seen.has(key)) {
    seen.add(key);
    articlesUniques.push(art);
  }
}

const fournisseurStatique = [
  {
  code_fournisseur: 'T6824',
  nom_fournisseur: 'AMANA MULTISERVICES GROUP',
  email: 'amanamultiservicesgroup@outlook.com', // à renseigner si disponible
  telephone: '0668349308',
  fax: '0668349308',
  Articles: articlesUniques
  },
  {
  code_fournisseur: 'T6970',
  nom_fournisseur: 'MSP Multiservice Pro',
  email: 'contact.ste.msp@gmail.com', // à renseigner si disponible
  telephone: '0700642166',
  fax: '0700642166',
  Articles: articlesUniques
  }
];

// ─── Résultat final ───────────────────────────────────────────────────────────
const result = Object.values(grouped);

// Ajouter le fournisseur statique à la fin
result.push(fournisseurStatique[0]);

result.push(fournisseurStatique[1]);

console.log(`\n📧 ${result.length} email(s) à envoyer`);
for (const f of result) {
  const tag = f.code_fournisseur === 'T6824' ? ' 🌟 [DESTINATAIRE GLOBAL]' : '';
  console.log(`   📬 ${f.nom_fournisseur}${tag}: ${f.Articles.length} article(s)`);
  f.Articles.forEach(art => {
    console.log(`      • ${art.code_article} (${art.quantite_demandee} ${art.unite})`);
  });
}

return result.map(f => ({ json: f }));

const item = $input.item.json;

// Générer UUID manuellement (sans crypto)
const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
  const r = Math.random() * 16 | 0;
  const v = c === 'x' ? r : (r & 0x3 | 0x8);
  return v.toString(16);
});

const now = new Date();
const annee = now.getFullYear();
const mois = String(now.getMonth() + 1).padStart(2, '0');
const jour = String(now.getDate()).padStart(2, '0');
const heure = String(now.getHours()).padStart(2, '0');
const minute = String(now.getMinutes()).padStart(2, '0');
const seconde = String(now.getSeconds()).padStart(2, '0');

const shortUuid = uuid.substring(0, 4).toUpperCase();
const numero_rfq = `RFQ-${annee}-${mois}${jour}${heure}${minute}${seconde}-${shortUuid}`;

const date_envoi = now.toISOString().slice(0, 19).replace('T', ' ');

return {
  json: {
    ...item,
    uuid: uuid,
    numero_rfq: numero_rfq,
    date_envoi: date_envoi
  }
};

// Récupérer les données originales depuis le nœud UUID
const originalData = $('🔑 Générer UUID + N° RFQ').item.json;

const rfq_uuid = originalData.uuid;
const articles = originalData.Articles;

console.log(`Transformation pour RFQ: ${originalData.numero_rfq}`);
console.log(`UUID: ${rfq_uuid}`);
console.log(`${articles.length} article(s) à transformer en lignes`);

// Créer une ligne pour chaque article
const lignes = [];
for (const article of articles) {
  lignes.push({
    json: {
      rfq_uuid: rfq_uuid,
      numero_da: article.numero_da,
      code_article: article.code_article,
      designation_article: article.designation,
      quantite_demandee: article.quantite_demandee,
      unite: article.unite,
      marque_souhaitee: article.marque_souhaitee || null
    }
  });
  console.log(`  -> Ligne: ${article.code_article} (${article.quantite_demandee} ${article.unite})`);
}

return lignes;

// ============================================
// 📝 Préparer Données Article (avec éclatement par DA)
// ============================================

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // Si le tableau "das" existe, créer une ligne par DA
  if (data.das && Array.isArray(data.das) && data.das.length > 0) {
    for (const da of data.das) {
      results.push({
        json: {
          article_code: data.code_article || data.article_code,
          designation: data.designation || data.designation_article,
          numero_da: da.numero,
          quantite_totale: da.quantite,
          unite: data.unite,
          marque_souhaitee: (data.marque_souhaitee === 'null' || !data.marque_souhaitee) ? null : data.marque_souhaitee
        }
      });
    }
  } else {
    // Sinon, utiliser les données directement
    results.push({
      json: {
        article_code: data.code_article || data.article_code,
        designation: data.designation || data.designation_article,
        numero_da: data.numero_da,
        quantite_totale: data.quantite_totale || data.quantite,
        unite: data.unite,
        marque_souhaitee: (data.marque_souhaitee === 'null' || !data.marque_souhaitee) ? null : data.marque_souhaitee
      }
    });
  }
}

return results;

// Récupérer les items depuis le nœud précédent
const items = $input.all();

// Grouper par famille
const groupedByFamily = {};

for (const item of items) {
  const famille = item.json.famille || "SANS_FAMILLE";

  if (!groupedByFamily[famille]) {
    groupedByFamily[famille] = [];
  }

  groupedByFamily[famille].push(item.json);
}

// Convertir en format pour n8n
const result = [];

for (const famille in groupedByFamily) {
  result.push({
    json: {
      famille: famille,
      nombre_articles: groupedByFamily[famille].length,
      articles: groupedByFamily[famille],
      // Quantité totale de la famille
      quantite_totale: groupedByFamily[famille].reduce((sum, article) => {
        return sum + (parseFloat(article.quantite) || 0);
      }, 0)
    }
  });
}

// Retourner les résultats groupés
return result;

// Récupérer toutes les familles
const allFamiliesData = $('groupe par famille').all();
const email_famille = $input.all();

console.log("=== REGROUPEMENT PAR FAMILLE ===");
console.log("Nombre de familles:", allFamiliesData.length);

// Grouper tous les emails par famille
const emailsByFamily = {};

email_famille.forEach(item => {
  const famille = item?.json?.famille;
  const email = item?.json?.email;

  if (famille && email) {
    if (!emailsByFamily[famille]) {
      emailsByFamily[famille] = [];
    }
    if (!emailsByFamily[famille].includes(email)) {
      emailsByFamily[famille].push(email);
    }
  }
});

console.log("Emails groupés:", emailsByFamily);

const result = [];

// Créer UNE SEULE entrée par famille
allFamiliesData.forEach(familleNode => {
  const familleData = familleNode.json;
  const familleName = familleData.famille;
  let emails = emailsByFamily[familleName] || [];

  console.log(`Famille ${familleName}: ${emails.length} email(s)`);

  // Si aucun email, utiliser l'email par défaut
  if (emails.length === 0) {
    emails = ["acheteur.1@jbel-annour.ma"];
  }

  // UNE SEULE entrée par famille
  result.push({
    json: {
      // Identifiant famille
      famille: familleName,

      // Statistiques
      nombre_articles: familleData.nombre_articles,
      quantite_totale: familleData.quantite_totale,

      // TOUS les emails dans UNE seule propriété
      emails_acheteurs: emails, // Tableau des emails
      liste_emails_formatee: emails.join(", "), // Version texte
      nombre_emails_famille: emails.length,

      // Articles complets
      articles: familleData.articles,

      // Pour les familles sans email
      statut: emails.length > 0 ? "Assignée" : "Non assignée",
      date_traitement: new Date().toISOString()
    }
  });
});

console.log(`\n✅ ${result.length} familles traitées (1 par famille)`);

// Vérification
console.log("\n📊 VÉRIFICATION:");
result.forEach(item => {
  const data = item.json;
  console.log(`${data.famille}: ${data.nombre_emails_famille} email(s) → ${data.liste_emails_formatee || "Aucun"}`);
});

return result;

const item = $input.item.json;

// Générer UUID manuellement (sans crypto)
const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
  const r = Math.random() * 16 | 0;
  const v = c === 'x' ? r : (r & 0x3 | 0x8);
  return v.toString(16);
});

const now = new Date();
const annee = now.getFullYear();
const mois = String(now.getMonth() + 1).padStart(2, '0');
const jour = String(now.getDate()).padStart(2, '0');
const heure = String(now.getHours()).padStart(2, '0');
const minute = String(now.getMinutes()).padStart(2, '0');
const seconde = String(now.getSeconds()).padStart(2, '0');

const shortUuid = uuid.substring(0, 4).toUpperCase();
const numero_rfq = `RFQ-${annee}-${mois}${jour}${heure}${minute}${seconde}-${shortUuid}`;

const date_envoi = now.toISOString().slice(0, 19).replace('T', ' ');

return {
  json: {
    ...item,
    uuid: uuid,
    numero_rfq: numero_rfq,
    date_envoi: date_envoi
  }
};

// Récupérer les données originales depuis le nœud UUID
const originalData = $('🔑 Générer UUID + N° RFQ1').item.json;

const rfq_uuid = originalData.uuid;
const articles = originalData.articles;

console.log(`Transformation pour RFQ: ${originalData.numero_rfq}`);
console.log(`UUID: ${rfq_uuid}`);
console.log(`${articles.length} article(s) à transformer en lignes`);

// Créer une ligne pour chaque article
const lignes = [];
for (const article of articles) {
  lignes.push({
    json: {
      rfq_uuid: rfq_uuid,
      numero_da: article.numero_da,
      code_article: article.code_article,
      designation_article: article.designation,
      quantite_demandee: article.quantite_totale,
      unite: article.unite,
      marque_souhaitee: article.marque_souhaitee || null
    }
  });
  console.log(`  -> Ligne: ${article.code_article} (${article.quantite_demandee} ${article.unite})`);
}

return lignes;

// Récupérer tous les items
const items = $input.all();

// Map pour tracker les combinaisons uniques
const seen = new Map();
const result = [];

for (const item of items) {
  const data = item.json;

  // Clé unique = Fournisseur + Article + DA
  const key = `${data.Fournisseur || data.Fournisseur}_${data.Article_Code}_${data.DA}`;

  if (!seen.has(key)) {
    seen.set(key, true);
    result.push({ json: data });
  }
}

return result;
